import{_ as e,o as a,c as t,V as o}from"./chunks/framework.d3b95951.js";const b=JSON.parse('{"title":"Installers","description":"","frontmatter":{},"headers":[],"relativePath":"reference/advanced/installers.md","filePath":"reference/advanced/installers.md","lastUpdated":1693551551000}'),l={name:"reference/advanced/installers.md"},s=o('<h1 id="installers" tabindex="-1">Installers <a class="header-anchor" href="#installers" aria-label="Permalink to &quot;Installers&quot;">​</a></h1><p>有关安装程序如何工作以及如何为托管安装创建自己的自定义安装程序/发行版的详细信息。</p><h2 id="current-installers" tabindex="-1">Current Installers <a class="header-anchor" href="#current-installers" aria-label="Permalink to &quot;Current Installers&quot;">​</a></h2><p>As of Volta 0.7.0, all of the official installers work in the same way:</p><ol><li>Unpack the Volta binaries</li><li>Call <code>volta setup</code> with the <code>volta</code> binary that was unpacked (see <a href="/reference/setup.html">volta setup</a> for more information)</li></ol><h3 id="windows-installer" tabindex="-1">Windows Installer <a class="header-anchor" href="#windows-installer" aria-label="Permalink to &quot;Windows Installer&quot;">​</a></h3><p>The Windows installer will unpack all of the binaries into <code>Program Files\\Volta</code> and add that folder to the System <code>Path</code> environment variable. It will also create the shims for the following tools in that directory:</p><ul><li><code>node</code></li><li><code>npm</code></li><li><code>npx</code></li><li><code>yarn</code></li></ul><h3 id="unix-installer" tabindex="-1">Unix Installer <a class="header-anchor" href="#unix-installer" aria-label="Permalink to &quot;Unix Installer&quot;">​</a></h3><p>The unix installer will unpack all of the binaries into <code>~/.volta/bin</code>, so they are installed only for the specific user.</p><h2 id="skipping-volta-setup" tabindex="-1">跳过 Volta 设置 <a class="header-anchor" href="#skipping-volta-setup" aria-label="Permalink to &quot;跳过 Volta 设置{#skipping-volta-setup}&quot;">​</a></h2><p>如果你想运行安装程序，但不希望你的配置文件脚本被 <code>volta setup</code> 修改，你可以将 <code>--skip-setup</code> 选项传递给安装程序:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://get.volta.sh</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">bash</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-s</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--skip-setup</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">警告</p><p>我们目前不支持在 Windows 上跳过 volta 设置。</p></div><h2 id="installing-old-versions" tabindex="-1">安装旧版本 <a class="header-anchor" href="#installing-old-versions" aria-label="Permalink to &quot;安装旧版本{#installing-old-versions}&quot;">​</a></h2><p>The default installer script provided by <a href="https://get.volta.sh" target="_blank" rel="noreferrer">get.volta.sh</a> only supports installing Volta 1.1.0 and above. If you wish to install an older version, you can install it using the following script on Unix, replacing <code>1.0.8</code> with the version you want to install:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">curl https://raw.githubusercontent.com/volta-cli/volta/8f2074f423c65405dfba9858d9bcf393c38ffb45/dev/unix/volta-install.sh | bash -s -- --version 1.0.8</span></span></code></pre></div><p>对于 Windows，您可以下载并安装你想要安装的特定版本的 <code>.msi</code> 文件。</p><div class="warning custom-block"><p class="custom-block-title">警告</p><p>Volta 不支持降级，因此为了降级，您需要完全卸载 Volta，然后安装较低版本。</p></div><h2 id="custom-installers" tabindex="-1">自定义安装 <a class="header-anchor" href="#custom-installers" aria-label="Permalink to &quot;自定义安装{#custom-installers}&quot;">​</a></h2><p>To create a custom installer / distribution method, there are two mandatory steps and one optional step:</p><h3 id="distribute-the-binaries" tabindex="-1">Distribute the Binaries <a class="header-anchor" href="#distribute-the-binaries" aria-label="Permalink to &quot;Distribute the Binaries&quot;">​</a></h3><p>The binaries themselves will need to be delivered to the target machine. The list of necessary binaries will be listed in <code>volta.manifest</code> in the release files. As of Volta 0.7.0, the required files are:</p><ul><li><code>volta[.exe]</code></li><li><code>volta-shim[.exe]</code></li><li><code>volta-migrate[.exe]</code></li></ul><p>These binaries all need to be distributed in the same directory as each other and that directory should be on the <code>PATH</code> so that calls to <code>volta</code> commands will work correctly.</p><h3 id="shim-directory" tabindex="-1">Shim Directory <a class="header-anchor" href="#shim-directory" aria-label="Permalink to &quot;Shim Directory&quot;">​</a></h3><p>The Volta shim directory needs to be added to the <code>PATH</code> as well, so that the shims will work as expected as well. The shim directory is at <code>$VOLTA_HOME/bin</code> (<code>%VOLTA_HOME%\\bin</code> on Windows), where <code>VOLTA_HOME</code> is defaulted to:</p><ul><li><code>~/.volta</code> on Unix</li><li><code>%LOCALAPPDATA%\\Volta</code> on Windows</li></ul><p>Updating the PATH can be managed manually, if desired, or you can call <code>volta setup</code> (as the official installers do, described above).</p><h3 id="custom-volta-home" tabindex="-1">自定义 Volta Home（可选） <a class="header-anchor" href="#custom-volta-home" aria-label="Permalink to &quot;自定义 Volta Home（可选）{#custom-volta-home}&quot;">​</a></h3><p>If you wish to use a different directory for the Volta data than the default <code>VOLTA_HOME</code> listed in the previous section, you need to set the environment variable <code>VOLTA_HOME</code> to that directory. If that is set, then <code>volta setup</code> will still work correctly for a custom data directory.</p>',31),i=[s];function n(r,c,d,h,p,u){return a(),t("div",null,i)}const f=e(l,[["render",n]]);export{b as __pageData,f as default};
